  ('social-worker-moex-07370', 'social-worker', 'social-worker-moex-101-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關消除對婦女一切形式歧視公約施行法（CEDAW）（以下簡稱公約）之描述，下列何者錯誤？', '["本法的目的是以消除對婦女一切形式歧視，健全婦女發展，落實保障性別人權及促進性別平等而制定", "本公約所揭示保障性別人權及促進性別平等之規定乃屬於聯合國所訂定，因此在國內並無法律之效力", "政府應依公約規定建立消除對婦女一切形式歧視報告制度，每四年提出國家報告並邀請有關學者專家 及民間團體審閱", "本法自中華民國101年1月1日起施行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "d90f7a035be7", "answer_pdf_sha1": "0daae4475aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會政策與社會立法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
